INSERT INTO `baiviet` (`id`, `tieu_de`, `hinh_anh`, `ngay_dang`, `mo_ta_ngan`, `noi_dung`) VALUES
('1', 'Cách chọn size giày bóng đá chuẩn nhất cho chân bè', 'assets/images/baiviet1.svg', '23-06-2026', 'Chân bè mang giày gì thoải mái? Xem ngay cẩm nang chọn size giày bóng đá cực chuẩn cho người chân bè ngang phong trào.', 'Bàn chân bè (bàn chân rộng bề ngang) luôn là nỗi lo lắng của nhiều cầu thủ khi chọn mua giày bóng đá. Mang một đôi giày quá chật ngang sẽ gây đau đớn, phồng rộp và ảnh hưởng lớn đến phong độ thi đấu. Dưới đây là các bước chọn size chuẩn:\n\n1. Đo kích thước bàn chân vào cuối ngày.\n2. Chọn phom giày thích hợp (phom da thật K-leather co giãn tốt như Mizuno Morelia hoặc Kamito).\n3. Tăng từ 0.5 đến 1 size nếu chọn các phom giày thon gọn như Nike Mercurial.'),
('2', 'So sánh đinh TF và đinh FG: Khi nào nên sử dụng?', 'assets/images/baiviet2.svg', '21-06-2026', 'Phân biệt chi tiết giữa giày bóng đá sân cỏ nhân tạo (TF) và sân cỏ tự nhiên (FG) để bảo vệ cổ chân tốt nhất khi vận động.', 'Sử dụng sai loại đinh giày trên mặt sân không phù hợp là nguyên nhân hàng đầu dẫn đến các chấn thương nghiêm trọng như lật sơ mi cổ chân, đứt dây chằng chéo trước. Hãy lưu ý:\n\n1. Đinh TF (Turf): Gồm nhiều đinh dăm nhỏ bằng cao su, thiết kế chuyên cho sân cỏ nhân tạo Việt Nam có độ dày cỏ thấp và mặt sân cứng. Hỗ trợ giảm chấn rất tốt.\n2. Đinh FG (Firm Ground): Gồm các đinh cao bằng nhựa cứng chịu lực, chuyên dụng cho sân cỏ tự nhiên có nền đất mềm, cỏ dày đạt chuẩn. Không dùng đinh FG trên sân cỏ nhân tạo cứng vì dễ trượt ngã và chấn thương.'),
('3', 'Top 5 đôi giày cỏ nhân tạo bán chạy nhất năm 2026', 'assets/images/baiviet3.svg', '18-06-2026', 'Tổng hợp những mẫu giày đá banh sân cỏ nhân tạo được người chơi phong trào ưa chuộng và săn lùng nhiều nhất phân khúc.', 'Đâu là những cái tên đang thống trị các sân cỏ phong trào năm nay?\n\n1. Nike Mercurial Vapor 15 Academy TF: Tốc độ và ôm chân tuyệt đối.\n2. Adidas Predator Accuracy.3 TF: Cảm giác bóng và các khu vực vân nổi kiểm soát tối ưu.\n3. Kamito Velocidad II TF: Giá thành hợp lý, phom bè cực êm cho người Việt.\n4. Mizuno Monarcida Neo II Select TF: Độ bền bỉ đáng kinh ngạc từ thương hiệu Nhật Bản.\n5. Puma Future Play TF: Cổ thun linh động cho lối chơi lắt léo.');
